import React, { useState } from 'react';

const FILTERS = ['all', 'active', 'completed'];

export default function TodoList() {
  const [todos, setTodos] = useState([
    { id: 't1', text: 'Read the prompt carefully', done: true },
    { id: 't2', text: 'Sketch the component API', done: false },
  ]);
  const [text, setText] = useState('');
  const [filter, setFilter] = useState('all');

  const add = (value) =>
    setTodos((t) => [...t, { id: String(Date.now()), text: value, done: false }]);
  const toggle = (id) =>
    setTodos((t) => t.map((x) => (x.id === id ? { ...x, done: !x.done } : x)));
  const remove = (id) => setTodos((t) => t.filter((x) => x.id !== id));

  const onSubmit = (e) => {
    e.preventDefault();
    const v = text.trim();
    if (v) {
      add(v);
      setText('');
    }
  };

  const visible = todos.filter((t) =>
    filter === 'active' ? !t.done : filter === 'completed' ? t.done : true
  );
  const remaining = todos.filter((t) => !t.done).length;

  return (
    <div style={{ maxWidth: 420 }}>
      <form onSubmit={onSubmit} style={{ display: 'flex', gap: 8 }}>
        <input
          value={text}
          onChange={(e) => setText(e.target.value)}
          placeholder="Add a todo…"
          style={{ flex: 1, padding: 8, fontSize: 15 }}
        />
        <button style={{ padding: '8px 16px', cursor: 'pointer' }}>Add</button>
      </form>

      <div style={{ display: 'flex', gap: 8, margin: '12px 0' }}>
        {FILTERS.map((f) => (
          <button
            key={f}
            onClick={() => setFilter(f)}
            style={{
              padding: '4px 10px',
              cursor: 'pointer',
              textTransform: 'capitalize',
              fontWeight: filter === f ? 700 : 400,
            }}
          >
            {f}
          </button>
        ))}
        <span style={{ marginLeft: 'auto', color: '#666' }}>{remaining} left</span>
      </div>

      <ul style={{ listStyle: 'none', padding: 0, margin: 0 }}>
        {visible.map((t) => (
          <li
            key={t.id}
            style={{ display: 'flex', alignItems: 'center', gap: 8, padding: '6px 0' }}
          >
            <input type="checkbox" checked={t.done} onChange={() => toggle(t.id)} />
            <span style={{ flex: 1, textDecoration: t.done ? 'line-through' : 'none', color: t.done ? '#999' : '#222' }}>
              {t.text}
            </span>
            <button onClick={() => remove(t.id)} aria-label="Delete" style={{ cursor: 'pointer' }}>
              ✕
            </button>
          </li>
        ))}
        {visible.length === 0 && <li style={{ color: '#999', padding: '6px 0' }}>Nothing here.</li>}
      </ul>
    </div>
  );
}

