import { Component } from '@angular/core';
import { NgModule } from '@angular/core';
import { BrowserModule } from '@angular/platform-browser';

interface Todo { id: string; text: string; done: boolean; }

@Component({
  selector: 'app-todo-list',
  template: `
    <div style="max-width: 420px;">
      <form (submit)="onSubmit(box.value); box.value=''" style="display: flex; gap: 8px;">
        <input #box placeholder="Add a todo…" style="flex: 1; padding: 8px; font-size: 15px;" />
        <button style="padding: 8px 16px; cursor: pointer;">Add</button>
      </form>

      <div style="display: flex; gap: 8px; margin: 12px 0; align-items: center;">
        <button
          *ngFor="let f of filters"
          (click)="filter = f"
          [style.font-weight]="filter === f ? 700 : 400"
          style="padding: 4px 10px; cursor: pointer; text-transform: capitalize;"
        >{{ f }}</button>
        <span style="margin-left: auto; color: #666;">{{ remaining }} left</span>
      </div>

      <ul style="list-style: none; padding: 0; margin: 0;">
        <li *ngFor="let t of visible; trackBy: trackById" style="display: flex; align-items: center; gap: 8px; padding: 6px 0;">
          <input type="checkbox" [checked]="t.done" (change)="toggle(t)" />
          <span [style.flex]="1" [style.text-decoration]="t.done ? 'line-through' : 'none'" [style.color]="t.done ? '#999' : '#222'">{{ t.text }}</span>
          <button (click)="remove(t.id)" aria-label="Delete" style="cursor: pointer;">✕</button>
        </li>
        <li *ngIf="visible.length === 0" style="color: #999; padding: 6px 0;">Nothing here.</li>
      </ul>
    </div>
  `,
})
export class TodoListComponent {
  filters = ['all', 'active', 'completed'];
  filter = 'all';
  todos: Todo[] = [
    { id: 't1', text: 'Read the prompt carefully', done: true },
    { id: 't2', text: 'Sketch the component API', done: false },
  ];

  onSubmit(value: string): void {
    const v = value.trim();
    if (!v) {
      return;
    }
    this.todos.push({ id: String(Date.now()), text: v, done: false });
  }

  toggle(t: Todo): void {
    t.done = !t.done;
  }

  remove(id: string): void {
    this.todos = this.todos.filter((x) => x.id !== id);
  }

  trackById(_i: number, t: Todo): string {
    return t.id;
  }

  get visible(): Todo[] {
    if (this.filter === 'active') {
      return this.todos.filter((t) => !t.done);
    }
    if (this.filter === 'completed') {
      return this.todos.filter((t) => t.done);
    }
    return this.todos;
  }

  get remaining(): number {
    return this.todos.filter((t) => !t.done).length;
  }
}

@Component({
  selector: 'app-root',
  template: `
    <div style="font-family: sans-serif; padding: 20px;">
      <h1>Todo List Demo</h1>
      <app-todo-list></app-todo-list>
    </div>
  `,
})
export class AppComponent {}

@NgModule({
  declarations: [AppComponent, TodoListComponent],
  imports: [BrowserModule],
  bootstrap: [AppComponent],
})
export class AppModule {}
